import { useNavigate } from 'react-router-dom';
import React, { useState, useEffect } from 'react';
import { FaRocket } from "react-icons/fa";
import axios from 'axios';
import Charts from "./components/Charts";
import './Home.css';

function Home() {
  const navigate = useNavigate();

  const [showProfile, setShowProfile] = useState(false);
  const [user, setUser] = useState(null);

  const [stats, setStats] = useState({
    totalPredictions: 0,
    avgSalary: 0,
    bestModelAccuracy: 0
  });

  // ✅ Logout
  const handleLogout = () => {
    localStorage.clear();
    navigate('/login');
  };

  // ✅ Load user + stats
  useEffect(() => {
    const storedUser = localStorage.getItem("user");

    if (!storedUser) {
      navigate('/login');
      return;
    }

    const userData = JSON.parse(storedUser);
    setUser(userData);

    // ✅ Total Predictions
    axios.get(`http://localhost:5000/stats/${userData.email}`)
      .then(res => {
        setStats(prev => ({
          ...prev,
          totalPredictions: res.data.totalPredictions || 0
        }));
      })
      .catch(err => console.log("Total Predictions Error:", err));

    // ✅ Average Salary
    axios.get(`http://localhost:5000/api/average-salary/${userData.email}`)
      .then(res => {
        setStats(prev => ({
          ...prev,
          avgSalary: res.data.average || 0
        }));
      })
      .catch(err => console.log("Average Salary Error:", err));

    // ✅ Best Model Accuracy (handle error safely)
    axios.get(`http://localhost:5000/api/best-model-accuracy`)
      .then(res => {
        setStats(prev => ({
          ...prev,
          bestModelAccuracy: res.data.accuracy || 0
        }));
      })
      .catch(err => {
        console.log("Accuracy API Error:", err);
        setStats(prev => ({
          ...prev,
          bestModelAccuracy: "N/A"
        }));
      });

  }, [navigate]);

  return (
    <div className="home-container">

      {/* NAVBAR */}
      <nav className="navbar">
        <h3>Dashboard</h3>

        <div className="right-section">

          {/* ✅ Profile Icon */}
          <div
            className="profile-circle"
            onClick={() => setShowProfile(!showProfile)}
          >
            <span>{user?.name?.charAt(0) || "U"}</span>
          </div>

         {showProfile && user && (
  <div className="profile-card">
    <h3>Profile 👤</h3>
    <p><b>Name:</b> {user.name || "Not Available"}</p>
    <p><b>Email:</b> {user.email || "Not Available"}</p>
    <p><b>Password:</b> ********</p>
  </div>
)}
          {/* Logout */}
          <button onClick={handleLogout} className="logout-btn">
            Logout
          </button>

        </div>
      </nav>

      {/* MAIN */}
      <div className="main-content">

        <h2 className="slogan">
          Know Your Worth, Predict With Confidence 🚀
        </h2>

        <div className="predict-btn-container">
          <button
            className="new-prediction-btn"
            onClick={() => navigate('/predict')}
          >
            <FaRocket style={{ marginRight: "8px" }} />
            New Salary Prediction
          </button>
        </div>

        {/* STATS */}
        <div className="stats-container">

          <div
            className="stat-card"
            onClick={() => navigate("/my-history")}
          >
            <h3>Total Predictions</h3>
            <p>{stats.totalPredictions}</p>
          </div>

          <div
            className="stat-card"
            onClick={() => navigate("/average-salary")}
          >
            <h3>Average Salary</h3>
            <p>
              {stats.avgSalary
                ? `₹${(stats.avgSalary / 100000).toFixed(1)} LPA`
                : "Loading..."}
            </p>
          </div>

          <div className="stat-card">
            <h3>Best Model Accuracy</h3>
            <p>{stats.bestModelAccuracy}%</p>
          </div>

        </div>

        {/* CHART */}
        <div style={{ marginTop: "40px" }}>
          <Charts />
        </div>

      </div>
    </div>
  );
}

export default Home;
